parameters.jsCode:
for (const item of $input.all()) {
  try {
    let rawOutput = item.json.output;

    rawOutput = String(rawOutput)
      .replace(/```json\n?/gi, "")
      .replace(/```\n?/g, "")
      .trim();

    rawOutput = rawOutput.replace(/\\'/g, "'");

    const parsedData = JSON.parse(rawOutput);
    const cleanData = parsedData.properties || parsedData;

    // Caso 1: output "message" (come nel tuo esempio)
    if (typeof cleanData.message === "string" && cleanData.message.trim()) {
      item.json = {
        list: !!cleanData.list,
        message: cleanData.message.trim(),
      };
      continue;
    }

    // Caso 2: output "card" (title/prompt) come nello script originale
    if (!cleanData.title || !cleanData.prompt) {
      throw new Error("Campi obbligatori mancanti: (message) oppure (title e prompt)");
    }

    item.json = {
      title: String(cleanData.title).trim(),
      style: cleanData.style ? String(cleanData.style).trim() : "",
      prompt: String(cleanData.prompt).trim(),
      negativeTags: cleanData.negativeTags ? String(cleanData.negativeTags).trim() : "",
    };
  } catch (error) {
    throw new Error("Errore nel parsing JSON: " + error.message);
  }
}

return $input.all();
